class Solution {
public:
    bool searchMatrix(vector<vector<int>>& m, int t) {
        if (m.empty()) return false;
        int R=m.size(), C=m[0].size(), lo=0, hi=R*C-1;
        while (lo<=hi) {
            int mid=(lo+hi)/2, v=m[mid/C][mid%C];
            if (v==t) return true;
            if (v<t) lo=mid+1; else hi=mid-1;
        }
        return false;
    }
};
